    public function getSourceContext(): Source
    {
        return new Source("{% extends 'base.html.twig' %}

{% block title %}Log in!{% endblock %}

{% block body %}
<div class=\"container mt-5\">
    <div class=\"row justify-content-center\">
        <div class=\"col-md-6\">
            <div class=\"card shadow\">
                <div class=\"form card-body p-4\">
                    <h1 class=\"text-center mb-4\">Se Connectez</h1>



                    <form method=\"post\">
                        {% if error %}
                            <div class=\"alert alert-danger\">{{ error.messageKey|trans(error.messageData, 'security') }}</div>
                        {% endif %}
                    
                        {% if app.user %}
                            <div class=\"mb-3\">
                                You are logged in as {{ app.user.userIdentifier }}, <a href=\"{{ logout_path() }}\">Logout</a>
                            </div>
                        {% endif %}
                    
                        <h1 class=\"h3 mb-3 font-weight-normal\">Please sign in</h1>
                        <label for=\"inputEmail\">Email</label>
                        <input type=\"email\" value=\"{{ last_username }}\" name=\"email\" id=\"inputEmail\" class=\"form-control\" autocomplete=\"email\" required autofocus>
                        <label for=\"inputPassword\">Password</label>
                        <input type=\"password\" name=\"password\" id=\"inputPassword\" class=\"form-control\" autocomplete=\"current-password\" required>
                        <input type=\"hidden\" name=\"_csrf_token\" data-controller=\"csrf-protection\" value=\"{{ csrf_token('authenticate') }}\">
                    
                        <div class=\"checkbox mb-3\">
                            <label>
                                <input type=\"checkbox\" name=\"_remember_me\"> Se souvenir de moi
                            </label>
                        </div>
                    
                        <button class=\"btn btn-lg btn-primary\" type=\"submit\">
                            Connexion
                        </button>

                        <a href=\"{{ path('app_register') }}\" class=\"d-block text-center mt-3\">
                            Vous n'avez pas de compte? <strong>Inscrivez-vous</strong>
                        </a>

                        
                    </form>
                </div>
            </div>
        </div>
    </div>
{% endblock %}
", "security/login.html.twig", "/home/yassine/Bureau/product/templates/security/login.html.twig");
